import { SeriesBaseStrategy } from './base-series.js';
import { GroupableSeriesHelper } from './groupable-series.js';
import { StackableSeriesHelper } from './stackable-series.js';
import type { XYChartSelectionRectangleMetadata } from '../../hooks/useSortRectangleDatapoints.js';
import type {
  BarSeriesWithDatapoints,
  DatapointMetadata,
  XYChartAxisInternal,
  XYChartBarSeriesInternal,
  XYChartVariantsInternal,
} from '../../types/xy-chart-internals.js';
import {
  BAR_VARIANT_SINGLE,
  type BarDatapoint,
  type BarSeriesVariant,
  type XYChartColorPalette,
  type XYChartData,
} from '../../types/xy-chart.js';
import { isBarSeries } from '../../utils/type-guards.js';
import type {
  BarSeriesConstructor,
  ControlFlowCommand,
  MutableProcessingContext,
} from '../types/processing-types.js';
import { getBarDatapoint } from '../utils/access-datapoint/get-bar-datapoints.js';
import {
  getChartOrientation,
  getDatumValue,
} from '../utils/access-datapoint/get-datapoints.js';
import { getLinearColor } from '../utils/coloring/get-linear-color-palette.js';
import { getBarSeriesVariant } from '../utils/grouping/get-variant.js';
import { isGrouping } from '../utils/grouping/group-bar-datapoints.js';
import {
  getBaselineCoordinate,
  isStackable,
} from '../utils/stacking/stack-datapoints.js';

export class BarSeriesStrategy extends SeriesBaseStrategy<XYChartSelectionRectangleMetadata> {
  private readonly stackHelper: StackableSeriesHelper;
  private readonly groupHelper: GroupableSeriesHelper;

  constructor(initializer: BarSeriesConstructor) {
    super(initializer);
    this.stackHelper = new StackableSeriesHelper();
    this.groupHelper = new GroupableSeriesHelper();
  }

  get axisIdToDimension() {
    return this.groupHelper.axisIdToDimension;
  }

  canHandle(
    seriesProps: XYChartVariantsInternal,
  ): seriesProps is XYChartBarSeriesInternal {
    return isBarSeries(seriesProps);
  }

  protected getSeriesId(
    datum: XYChartData,
    seriesProps: XYChartBarSeriesInternal,
  ): string {
    return getDatumValue(
      datum,
      seriesProps.seriesIdAccessor,
    )?.toString() as string;
  }

  protected createSeries(
    seriesId: string,
    seriesProps: XYChartBarSeriesInternal,
    xAxis: XYChartAxisInternal,
    yAxis: XYChartAxisInternal,
  ) {
    return {
      id: seriesId,
      type: seriesProps.type,
      data: [],
      xAxisId: xAxis.id,
      yAxisId: yAxis.id,
      labelAccessor: seriesProps.labelAccessor,
    };
  }

  protected createSeriesMetadata(
    datum: XYChartData,
    seriesProps: XYChartBarSeriesInternal,
    xAxis: XYChartAxisInternal,
    yAxis: XYChartAxisInternal,
    seriesId: string,
    context: MutableProcessingContext,
    variant?: BarSeriesVariant,
  ) {
    const { intl, seriesIndexes } = context;
    const { nameAccessor: seriesNameAccessor } = seriesProps;

    const seriesIndex = this.getOrCreateSeriesIndex(seriesId, seriesIndexes);
    const seriesName = this.getSeriesName(intl, seriesIndex, undefined, {
      seriesNameAccessor,
      datum,
    });

    const color = this.getColor(
      datum,
      seriesProps,
      context.colorPalette,
      seriesName,
      seriesIndex,
    );

    return {
      xAxis,
      yAxis,
      ...color,
      name: seriesName,
      variant: variant ?? BAR_VARIANT_SINGLE,
      actions: seriesProps.actions,
      chartOrientation: getChartOrientation(seriesProps),
    };
  }

  private handleStackingAndGrouping(
    datapoint: BarDatapoint,
    seriesProps: XYChartBarSeriesInternal,
    xAxis: XYChartAxisInternal,
    yAxis: XYChartAxisInternal,
    chartOrientation: 'vertical' | 'horizontal' | 'both',
    seriesId: string,
    isSeriesVisible: boolean,
  ): {
    calcDatapoint: BarDatapoint;
    datapointMetadata: DatapointMetadata;
    shouldContinue: boolean;
    variant: BarSeriesVariant;
  } {
    let shouldContinue = false;
    let datapointMetadata: DatapointMetadata = {
      isGap: false,
      baseline: getBaselineCoordinate(chartOrientation),
    };

    const canStack = isStackable(
      seriesProps.variant,
      chartOrientation,
      xAxis,
      yAxis,
    );

    const canGroup = isGrouping(
      seriesProps.variant,
      chartOrientation,
      xAxis,
      yAxis,
    );

    let calcDatapoint: BarDatapoint | undefined;

    if (!isSeriesVisible) {
      return {
        calcDatapoint: calcDatapoint ?? datapoint,
        datapointMetadata,
        shouldContinue,
        variant: getBarSeriesVariant(canStack, canGroup),
      };
    }

    if (canStack) {
      ({ calcDatapoint, datapointMetadata, shouldContinue } =
        this.stackHelper.processStackedDatapoint(
          datapoint,
          chartOrientation as 'vertical' | 'horizontal',
          xAxis,
          yAxis,
          datapointMetadata,
        ));
    }

    if (canGroup) {
      ({ datapointMetadata } = this.groupHelper.processGroupDatapoint(
        datapoint,
        chartOrientation as 'vertical' | 'horizontal',
        xAxis,
        yAxis,
        seriesId,
        datapointMetadata,
      ));
    }

    return {
      calcDatapoint: calcDatapoint ?? datapoint,
      datapointMetadata,
      shouldContinue,
      variant: getBarSeriesVariant(canStack, canGroup),
    };
  }

  protected preprocessImpl(
    data: XYChartData[],
    seriesProps: XYChartBarSeriesInternal,
    xAxis: XYChartAxisInternal,
    yAxis: XYChartAxisInternal,
    context: MutableProcessingContext,
  ): ControlFlowCommand {
    const chartOrientation = getChartOrientation(seriesProps);
    if (chartOrientation === undefined || chartOrientation === 'both') {
      return;
    }

    const canStack = isStackable(
      seriesProps.variant,
      chartOrientation,
      xAxis,
      yAxis,
    );

    const canGroup = isGrouping(
      seriesProps.variant,
      chartOrientation,
      xAxis,
      yAxis,
    );

    if (!canStack && !canGroup) {
      return;
    }

    const filteredSeriesIds = context?.filteredSeriesIds;

    for (const datum of data) {
      const datapoint = this.getDatapoint(datum, seriesProps, xAxis, yAxis);

      if (datapoint) {
        const seriesId = this.getSeriesId(datum, seriesProps);
        const isSeriesVisible =
          filteredSeriesIds === undefined || filteredSeriesIds.has(seriesId);

        if (!isSeriesVisible) {
          continue;
        }

        if (canStack) {
          this.stackHelper.processStackDomain(
            datapoint,
            chartOrientation,
            xAxis,
            yAxis,
            seriesId,
          );
        }

        if (canGroup) {
          this.groupHelper.processGroupDomain(
            datapoint,
            chartOrientation,
            xAxis,
            yAxis,
            seriesId,
          );
        }
      }
    }
  }

  protected processImpl(
    datum: XYChartData,
    seriesProps: XYChartBarSeriesInternal,
    xAxis: XYChartAxisInternal,
    yAxis: XYChartAxisInternal,
    datapoint: BarDatapoint,
    context: MutableProcessingContext,
  ) {
    const { seriesMap, seriesToMetadata } = context;

    const seriesId = this.getSeriesId(datum, seriesProps);

    const chartOrientation = getChartOrientation(seriesProps);
    if (chartOrientation === undefined) {
      return 'continue';
    }

    const isSeriesVisible =
      context.filteredSeriesIds === undefined ||
      context.filteredSeriesIds.has(seriesId);

    const { calcDatapoint, datapointMetadata, shouldContinue, variant } =
      this.handleStackingAndGrouping(
        datapoint,
        seriesProps,
        xAxis,
        yAxis,
        chartOrientation,
        seriesId,
        isSeriesVisible,
      );

    if (shouldContinue) {
      return 'continue';
    }

    let currentSeries: BarSeriesWithDatapoints | undefined =
      seriesMap.get(seriesId);

    if (!currentSeries) {
      currentSeries = this.createSeries(seriesId, seriesProps, xAxis, yAxis);

      this.registerSeries(currentSeries, seriesId, context);

      const metadata = this.createSeriesMetadata(
        datum,
        seriesProps,
        xAxis,
        yAxis,
        seriesId,
        context,
        variant,
      );

      seriesToMetadata.set(currentSeries, {
        ...metadata,
        isVisible: isSeriesVisible,
      });
    }

    if (datapoint.label) {
      currentSeries.hasLabels = true;
    }

    this.registerDatapoint(
      datapoint,
      datapointMetadata,
      currentSeries,
      context,
    );

    this.updateAxisDomains(
      calcDatapoint,
      xAxis,
      yAxis,
      context.axisIdToScaleDomain,
      isSeriesVisible,
    );

    if (isSeriesVisible) {
      context.axisWithSeries.add(xAxis.id);
      context.axisWithSeries.add(yAxis.id);

      this.addValue({
        series: currentSeries,
        datapoint,
      });
    }
  }

  getColor(
    datum: XYChartData,
    seriesProps: XYChartBarSeriesInternal,
    configColorPalette: XYChartColorPalette | undefined,
    seriesName: string,
    seriesIndex: number,
  ) {
    return getLinearColor(
      datum,
      seriesProps,
      configColorPalette,
      seriesName,
      seriesIndex,
    );
  }

  getDatapoint(
    datum: XYChartData,
    seriesProps: XYChartBarSeriesInternal,
    xAxis: XYChartAxisInternal,
    yAxis: XYChartAxisInternal,
  ) {
    return getBarDatapoint(datum, seriesProps, xAxis, yAxis);
  }
}
